request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?choreo ?taskA ?nameA ?taskB ?nameB WHERE {
  ?model a bboExt:Model ;
         bbo:name ?modelName ;
         tai:normalizedId "0b21c69687b64d8886fb7cc5dc56ff6c" .

  ?taskA a bboExt:ChoreographyTask ;
         bbo:name ?nameA ;
         tai:belongsTo ?choreo .
  FILTER(CONTAINS(LCASE(STR(?nameA)), LCASE("genehmigten uund unterzeichneetn Urlaubsantrag weiterleiten")))

  ?taskB a bboExt:ChoreographyTask ;
         bbo:name ?nameB ;
         tai:belongsTo ?choreo .
  FILTER(CONTAINS(LCASE(STR(?nameB)), LCASE("ausgefüllter und unterschriebener Antrag")))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?task ?id ?name WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "0b21c69687b64d8886fb7cc5dc56ff6c" .
  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo .
  ?choreo tai:belongsTo ?model .

  OPTIONAL { ?task bbo:id ?id . }
  OPTIONAL { ?task bbo:name ?name . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?modelName ?choreo ?choreoType ?seqCount WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "0b21c69687b64d8886fb7cc5dc56ff6c" ;
         bbo:name ?modelName .

  ?choreo tai:belongsTo ?model .
  OPTIONAL { ?choreo a ?choreoType . }

  OPTIONAL {
    SELECT (COUNT(DISTINCT ?seq) AS ?seqCount) WHERE {
      ?seq a bbo:SequenceFlow ;
           bbo:has_sourceRef ?s ;
           bbo:has_targetRef ?t .
      ?s tai:belongsTo ?choreo .
      ?t tai:belongsTo ?choreo .
    }
  }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?orig ?norm WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?orig . }
  OPTIONAL { ?model tai:normalizedId ?norm . }
  FILTER(
    (BOUND(?norm) && CONTAINS(STR(?norm), "0b21c69687b64d8886fb7cc5dc56ff6c")) ||
    (BOUND(?orig) && CONTAINS(STR(?orig), "0b21c69687b64d8886fb7cc5dc56ff6c"))
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?taskBeforeName ?taskAfterName ?taskBefore ?taskAfter WHERE {
  ?model a bboExt:Model ;
         tai:originalId "0b21c69687b64d8886fb7cc5dc56ff6c" .

  # Candidate tasks connected by sequence flows
  ?taskBefore a bboExt:ChoreographyTask ;
              bbo:name ?taskBeforeName ;
              tai:belongsTo ?choreo .
  ?choreo tai:belongsTo ?model .

  ?taskAfter a bboExt:ChoreographyTask ;
            bbo:name ?taskAfterName ;
            tai:belongsTo ?choreo .

  FILTER(
    CONTAINS(LCASE(STR(?taskBeforeName)), LCASE("genehmigter")) ||
    CONTAINS(LCASE(STR(?taskBeforeName)), LCASE("unterzeichn")) ||
    CONTAINS(LCASE(STR(?taskBeforeName)), LCASE("weiter"))
  )
  FILTER(
    CONTAINS(LCASE(STR(?taskAfterName)), LCASE("ausgefüllter")) ||
    CONTAINS(LCASE(STR(?taskAfterName)), LCASE("unterschr"))
  )

  # Check if taskAfter is reachable after taskBefore (i.e., taskBefore executes before taskAfter)
  ?taskBefore ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?taskAfter .
}
LIMIT 25
